export const getStateBySlug = (slug: string): USAStateData | undefined =>
  usaStates.find(s => s.slug === slug);

export const getUSACityBySlug = (stateSlug: string, citySlug: string): USACityData | undefined => {
  const state = getStateBySlug(stateSlug);
  return state?.cities.find(c => c.slug === citySlug);
};

export const totalUSACities = usaStates.reduce((acc, s) => acc + s.cities.length, 0);
